Javascript.validate:
var val = Services.getValue(OutstandingBalance.dataBinding );
var err = validateCurrencyValue( val,'99999999.99');
if( null == err )
{	var fVal = WPU.formatToTwoDP(val);
	Services.setValue(OutstandingBalance.dataBinding, fVal);
}
return err;

