function DefaultCurrency449() {}
DefaultCurrency449.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency449.tabIndex = -1;
DefaultCurrency449.maxLength = 1;
DefaultCurrency449.isReadOnly = function(){return true;}
DefaultCurrency449.isTemporary = function(){return true;}
DefaultCurrency449.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency449.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
